+function latestCollapsedTranscriptTimestamp(
+	segments: readonly MemorySegment[],
+	sessionId: string,
+): number {
+	let latest = -Infinity;
+	for (const segment of segments) {
+		if (segment.session_id === sessionId && segment.ended_at > latest) {
+			latest = segment.ended_at;
+		}
+	}
+	return latest;
+}
